  const hoursRemaining = (expiresDate.getTime() - Date.now()) / 3_600_000;
  const isExpiringSoon = hoursRemaining < 24;

  return (
    <div className="min-h-screen bg-zinc-50">
      <header className="sticky top-0 z-10 border-b border-zinc-200 bg-white/80 backdrop-blur">
        <div className="mx-auto max-w-4xl flex items-center justify-between px-6 py-4">
          <Link href="/" className="text-lg font-bold text-zinc-900">
            Artifact Hub
          </Link>
          <span className="text-sm text-zinc-400">Shared artifact</span>
        </div>
      </header>

      <main className="mx-auto max-w-4xl px-6 py-8 space-y-6">
        {isExpiringSoon && (
          <div className="rounded-lg border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800">
            This link expires{" "}
            {expiresDate.toLocaleDateString("en-US", {
              month: "short",
              day: "numeric",
              year: "numeric",
            })}
            .
          </div>
        )}

        <div>
          <h1 className="text-2xl font-bold text-zinc-900">{artifact.title}</h1>
          {artifact.description && (
            <p className="mt-1 text-zinc-600">{artifact.description}</p>
          )}
          {artifact.tags.length > 0 && (
            <div className="mt-2 flex flex-wrap gap-1">
              {artifact.tags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center rounded-full bg-zinc-100 px-2.5 py-0.5 text-xs text-zinc-600"
                >
                  {tag}
                </span>
              ))}
            </div>
          )}
        </div>

        {signedUrl ? (
          <ArtifactPreview
            type={artifact.type}
            signedUrl={signedUrl}
            title={artifact.title}
          />
        ) : (
          <div className="rounded-xl border border-zinc-200 bg-zinc-50 p-8 text-center text-zinc-500">
            Preview unavailable.
          </div>
        )}
      </main>
    </div>
  );
}

