import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { registerArtifactTools } from "./tools/artifacts.js";
import { registerShareTools } from "./tools/share.js";
import { registerSummarizeTools } from "./tools/summarize.js";
import { registerPublishTools } from "./tools/publish.js";
import { registerFeedbackTools } from "./tools/feedback.js";

const server = new McpServer({
  name: "artifact-hub",
  version: "0.1.0",
});

registerArtifactTools(server);
registerShareTools(server);
registerSummarizeTools(server);
registerPublishTools(server);
registerFeedbackTools(server);

const transport = new StdioServerTransport();
await server.connect(transport);

const rawBase = process.env.ARTIFACT_HUB_BASE_URL ?? "http://localhost:3000";
const baseUrl = rawBase.replace(/\/$/, "");
const apiKey = process.env.ARTIFACT_HUB_ADMIN_KEY ?? "";

async function request(path: string, init: RequestInit = {}): Promise<unknown> {
  const res = await fetch(`${baseUrl}${path}`, {
    ...init,
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
      ...(init.headers ?? {}),
    },
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({ error: res.statusText }));
    const msg = (err as Record<string, unknown>).error;
    throw new Error(typeof msg === "string" ? msg : `HTTP ${res.status}`);
  }

  return res.json();
}

export function get(path: string): Promise<unknown> {
  return request(path, { method: "GET" });
}

export function post(path: string, body: unknown): Promise<unknown> {
  return request(path, { method: "POST", body: JSON.stringify(body) });
}

export function patch(path: string, body: unknown): Promise<unknown> {
  return request(path, { method: "PATCH", body: JSON.stringify(body) });
}

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import * as client from "../client.js";

interface ArtifactPublic {
  id: string;
  title: string;
  description: string | null;
  tags: string[];
  type: string;
  visibility: string;
  file_size: number | null;
  original_filename: string | null;
  created_at: string;
}

interface FeedbackItem {
  id: string;
  reviewer_name: string;
  reviewer_role: string | null;
  feedback_type: string;
  status: string;
  comment: string;
  created_at: string;
}

function fmt(iso: string): string {
  return new Date(iso).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
}

export function registerArtifactTools(server: McpServer): void {
  server.tool(
    "list_artifacts",
    "List published artifacts with optional filters. Returns IDs, titles, types, tags, and visibility.",
    {
      type: z.enum(["pdf", "image", "html"]).optional().describe("Filter by artifact type"),
      tags: z.array(z.string()).optional().describe("Filter by tags (any match)"),
      visibility: z
        .enum(["public", "unlisted"])
        .optional()
        .describe("Filter by visibility. Omit to return all."),
      limit: z.number().int().min(1).max(100).optional().describe("Max results (default 50)"),
      offset: z.number().int().min(0).optional().describe("Pagination offset (default 0)"),
    },
    async ({ type, tags, visibility, limit, offset }) => {
      const params = new URLSearchParams();
      if (type) params.set("type", type);
      if (tags?.length) params.set("tags", tags.join(","));
      if (visibility) params.set("visibility", visibility);
      if (limit !== undefined) params.set("limit", String(limit));
      if (offset !== undefined) params.set("offset", String(offset));

      const qs = params.size > 0 ? `?${params.toString()}` : "";
      const data = (await client.get(`/api/mcp/artifacts${qs}`)) as ArtifactPublic[];

      if (data.length === 0) {
        return {
          content: [{ type: "text" as const, text: "No artifacts found matching the given filters." }],
        };
      }

      const lines = data.map((a, i) => {
        const tagStr = a.tags.length ? `\n   Tags: ${a.tags.join(", ")}` : "";
        return `${i + 1}. [${a.type.toUpperCase()}] ${a.title}\n   ID: ${a.id} | Visibility: ${a.visibility}${tagStr}\n   Published: ${fmt(a.created_at)}`;
      });

      return {
        content: [{
          type: "text" as const,
          text: `Found ${data.length} artifact${data.length === 1 ? "" : "s"}.\n\n${lines.join("\n\n")}`,
        }],
      };
    }
  );

  server.tool(
    "get_artifact",
    "Get full artifact details including all feedback and a signed 1-hour preview URL. Works for both public and unlisted artifacts.",
    {
      artifact_id: z.string().describe("The artifact UUID"),
    },
    async ({ artifact_id }) => {
      const data = (await client.get(`/api/mcp/artifacts/${artifact_id}`)) as {
        artifact: ArtifactPublic;
        feedback: FeedbackItem[];
        signedUrl: string;
      };

      const { artifact, feedback, signedUrl } = data;
      const desc = artifact.description ? `\nDescription: ${artifact.description}` : "";
      const tagStr = artifact.tags.length ? `\nTags: ${artifact.tags.join(", ")}` : "";

      const feedbackBlock =
        feedback.length === 0
          ? "No feedback yet."
          : feedback
              .map((f, i) => {
                const role = f.reviewer_role ? ` (${f.reviewer_role})` : "";
                return `${i + 1}. [${f.feedback_type}] ● ${f.status}\n   ${f.reviewer_name}${role} — ${fmt(f.created_at)}\n   "${f.comment}"`;
              })
              .join("\n\n");

      const previewSection = signedUrl
        ? `\nPreview URL (valid 1 hour):\n${signedUrl}`
        : "\nPreview URL: unavailable";

      const text = [
        `Artifact: ${artifact.title}`,
        `ID: ${artifact.id} | Type: ${artifact.type.toUpperCase()} | Visibility: ${artifact.visibility}`,
        `Published: ${fmt(artifact.created_at)}${desc}${tagStr}`,
        previewSection,
        `\nFeedback (${feedback.length} item${feedback.length === 1 ? "" : "s"}):`,
        "",
        feedbackBlock,
      ].join("\n");

      return { content: [{ type: "text" as const, text }] };
    }
  );
}

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import * as client from "../client.js";

interface SummaryData {
  overall_assessment: string;
  open_issues: string[];
  suggestions: string[];
  questions: string[];
  approval_count: number;
}

interface SummarizeResponse {
  summary: {
    artifact_id: string;
    summary: SummaryData;
    feedback_count: number;
    model: string | null;
    generated_at: string;
  };
  feedbackCount: number;
}

export function registerSummarizeTools(server: McpServer): void {
  server.tool(
    "summarize_feedback",
    "Get an AI-generated structured summary of all feedback for an artifact. Returns the cached result if feedback is unchanged. Use force_refresh=true to regenerate.",
    {
      artifact_id: z.string().describe("The artifact UUID"),
      force_refresh: z
        .boolean()
        .optional()
        .describe("Force regeneration even if a current summary exists (default false)"),
    },
    async ({ artifact_id, force_refresh }) => {
      const data = (await client.post("/api/mcp/summarize", {
        artifact_id,
        force_refresh: force_refresh ?? false,
      })) as SummarizeResponse;

      const s = data.summary.summary;
      const meta = `Generated from ${data.feedbackCount} feedback item${data.feedbackCount === 1 ? "" : "s"}`;
      const modelTag = data.summary.model ? ` · ${data.summary.model}` : "";

      const issueLines =
        s.open_issues.length > 0
          ? `\nOpen Issues (${s.open_issues.length}):\n${s.open_issues.map((x) => `• ${x}`).join("\n")}`
          : "";
      const suggLines =
        s.suggestions.length > 0
          ? `\nSuggestions (${s.suggestions.length}):\n${s.suggestions.map((x) => `• ${x}`).join("\n")}`
          : "";
      const qLines =
        s.questions.length > 0
          ? `\nQuestions (${s.questions.length}):\n${s.questions.map((x) => `• ${x}`).join("\n")}`
          : "";
      const approvalLine =
        s.approval_count > 0 ? `\nApprovals: ${s.approval_count}` : "";

      const text = [
        "Feedback Summary",
        `${meta}${modelTag}`,
        "",
        "Overall Assessment:",
        s.overall_assessment,
        issueLines,
        suggLines,
        qLines,
        approvalLine,
      ]
        .filter((x) => x !== "")
        .join("\n");

      return { content: [{ type: "text" as const, text }] };
    }
  );
}

